app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit()
  }
})

app.on('activate', () => {
  if (BrowserWindow.getAllWindows().length === 0) {
    createWindow()
  }
})

app.on('before-quit', (e) => {
  if (shutdownDone) return
  // Prevent default quit to do async graceful shutdown, then re-quit.
  e.preventDefault()
  isQuitting = true
  const bridge = getPythonBridge()

  let timedOut = false
  const timer = setTimeout(() => {
    timedOut = true
    bridge.kill()
    shutdownDone = true
    app.quit()
  }, SHUTDOWN_TIMEOUT_MS)

  bridge.shutdown()
    .then(() => {
      clearTimeout(timer)
      if (!timedOut) {
        shutdownDone = true
        app.quit()
      }
    })
    .catch(() => {
      clearTimeout(timer)
      if (!timedOut) {
        bridge.kill()
        shutdownDone = true
        app.quit()
      }
    })
})

import { spawn, ChildProcess } from 'child_process'
import path from 'path'
import crypto from 'crypto'
import { app } from 'electron'

const REQUEST_TIMEOUT_MS = 30_000
// 20MB: cover image data URIs (base64) and large URL lists can exceed 1MB
const MAX_BUFFER_SIZE = 20 * 1024 * 1024
const MAX_RESTARTS = 5

interface PendingRequest {
  resolve: (value: unknown) => void
  reject: (reason: unknown) => void
  timer: NodeJS.Timeout
}

export class PythonBridge {
  private process: ChildProcess | null = null
  private pendingRequests = new Map<string, PendingRequest>()
  private buffer = ''
  private restartTimer: NodeJS.Timeout | null = null
  private isShuttingDown = false
  private restartCount = 0
  private notificationHandlers = new Map<string, (params: unknown) => void>()

  constructor() {
    this.start()
  }

  private getPythonPath(): string {
    const isDev = !app.isPackaged
    const isWin = process.platform === 'win32'
    if (isDev) {
      return isWin ? 'python' : 'python3'
    }
    const exeName = isWin ? 'python.exe' : 'python'
    return path.join(process.resourcesPath, 'python', exeName)
  }

  private getScriptPath(): string | null {
    const isDev = !app.isPackaged
    if (isDev) {
      return path.join(app.getAppPath(), 'python', 'ipc_server.py')
    }
    return null
  }

  private handleStdoutData(data: Buffer, proc: ChildProcess) {
    if (this.process !== proc) return
    this.buffer += data.toString()

    const lines = this.buffer.split('\n')
    this.buffer = lines.pop() || ''

    for (const line of lines) {
      if (line.trim()) {
        if (line.length > MAX_BUFFER_SIZE) {
          console.error('IPC single message too large, discarding')
          for (const [, pending] of this.pendingRequests) {
            clearTimeout(pending.timer)
            pending.reject(new Error('IPC response too large'))
          }
          this.pendingRequests.clear()
          this.buffer = ''
          this.handleProcessFailure('IPC response too large')
          return
        }
        try {
          const response = JSON.parse(line)
          if (response.id) {
            const pending = this.pendingRequests.get(response.id)
            if (pending) {
              clearTimeout(pending.timer)
              this.pendingRequests.delete(response.id)
              if (response.error) {
                const err = new Error(response.error.message) as Error & { code?: number }
                if (typeof response.error.code === 'number') {
                  err.code = response.error.code
                }
                pending.reject(err)
              } else {
                pending.resolve(response.result)
                this.restartCount = 0
              }
            }
          } else if (response.method) {
            this.onNotification(response.method, response.params)
          }
        } catch (e) {
          console.error('Failed to parse IPC response:', e)
        }
      }
    }

    if (this.buffer.length > MAX_BUFFER_SIZE) {
      console.error('IPC buffer overflow, discarding incomplete message')
      this.buffer = ''
      for (const [, pending] of this.pendingRequests) {
        clearTimeout(pending.timer)
        pending.reject(new Error('IPC response too large'))
      }
      this.pendingRequests.clear()
      this.handleProcessFailure('IPC buffer overflow')
    }
  }

  private start() {
    const pythonPath = this.getPythonPath()
    const scriptPath = this.getScriptPath()
    const args = scriptPath ? [scriptPath] : []

    this.process = spawn(pythonPath, args, {
      stdio: ['pipe', 'pipe', 'pipe'],
      windowsHide: true,
      env: { ...process.env, PYTHONIOENCODING: 'utf-8' },
    })
    const proc = this.process

    proc.stdout?.on('data', (data: Buffer) => this.handleStdoutData(data, proc))

    proc.stderr?.on('data', (data: Buffer) => {
      if (this.process !== proc) return
      console.error('Python stderr:', data.toString())
    })

    proc.on('exit', (code) => {
      if (this.process !== proc) return
      this.handleProcessFailure(`Python process exited with code ${code}`)
    })

    proc.on('error', (err) => {
      if (this.process !== proc) return
      console.error('Failed to start Python process:', err)
      this.handleProcessFailure(`Python process error: ${err.message}`)
    })
  }

  private handleProcessFailure(message: string) {
    for (const [, pending] of this.pendingRequests) {
      clearTimeout(pending.timer)
      pending.reject(new Error(message))
    }
    this.pendingRequests.clear()

    if (this.process) {
      const oldProc = this.process
      oldProc.stdout?.removeAllListeners('data')
      oldProc.stderr?.removeAllListeners('data')
      try { oldProc.kill() } catch { /* already dead */ }
      oldProc.removeAllListeners()
      this.process = null
    }

    if (!this.isShuttingDown && this.restartCount < MAX_RESTARTS) {
      this.restartCount++
      this.restartTimer = setTimeout(() => {
        this.start()
      }, 2000)
    } else if (this.restartCount >= MAX_RESTARTS) {
      console.error(`Python bridge exceeded max restart attempts (${MAX_RESTARTS})`)
    }
  }

  onNotification(method: string, params: unknown) {
    const handler = this.notificationHandlers.get(method)
    if (handler) {
      handler(params)
    }
  }

  setNotificationHandler(method: string, handler: (params: unknown) => void) {
    this.notificationHandlers.set(method, handler)
  }

  async call(method: string, params: Record<string, unknown> = {}): Promise<unknown> {
    const proc = this.process
    if (!proc) {
      throw new Error('Python process not running')
    }

    if (!proc.stdin?.writable) {
      throw new Error('Python process stdin not writable')
    }

    // Guard: reject if process was replaced between the snapshot and here
    if (this.process !== proc) {
      throw new Error('Python process was replaced during call')
    }

    const id = crypto.randomUUID()
    const request = { jsonrpc: '2.0', id, method, params }

    return new Promise((resolve, reject) => {
      const timer = setTimeout(() => {
        if (this.pendingRequests.has(id)) {
          this.pendingRequests.delete(id)
          reject(new Error('Request timeout'))
        }
      }, REQUEST_TIMEOUT_MS)

      this.pendingRequests.set(id, { resolve, reject, timer })
      try {
        proc.stdin!.write(JSON.stringify(request) + '\n')
      } catch (_err) {
        clearTimeout(timer)
        this.pendingRequests.delete(id)
        reject(new Error('Failed to write to Python process stdin'))
      }
    })
  }

  kill() {
    this.isShuttingDown = true
    if (this.restartTimer) {
      clearTimeout(this.restartTimer)
      this.restartTimer = null
    }
    if (this.process) {
      this.process.kill()
      this.process = null
    }
  }

  async shutdown(): Promise<void> {
    if (!this.process) return
    try {
      await this.call('shutdown', {})
    } catch {
      // Shutdown RPC may fail if process is already dead
    }
    this.kill()
  }
}

let bridge: PythonBridge | null = null

export function getPythonBridge(): PythonBridge {
  if (!bridge) {
    bridge = new PythonBridge()
  }
  return bridge
}

import { useState, useEffect, useCallback, useRef } from 'react'
import { useTheme } from './hooks/useTheme'
import { useSettingsStore, subscribeToBlacklistChanges } from './stores/useSettingsStore'
import { useConfig } from './hooks/useIpc'
import { Sidebar } from './components/Sidebar'
import { SearchPage } from './pages/SearchPage'
import { DownloadPage } from './pages/DownloadPage'
import { FavouritesPage } from './pages/FavouritesPage'
import { SettingsPage } from './pages/SettingsPage'
import { Toast } from './components/common/Toast'
import { ComicInfoDrawer } from './components/ComicInfoDrawer'
import { ComicReaderModal } from './components/ComicReaderModal'
import { useDrawerStore } from './stores/useDrawerStore'
import { useReaderStore } from './stores/useReaderStore'

function App() {
  const {
    sfwToastDismissed,
    setThemeMode, setSfwMode, dismissSfwToast, setTagBlacklist,
  } = useSettingsStore()
  const { getConfig, setConfig } = useConfig()
  useTheme()

  const [showSfwToast, setShowSfwToast] = useState(false)
  const subscribedRef = useRef(false)
  const unsubRef = useRef<(() => void) | null>(null)

  useEffect(() => {
    getConfig().then((result) => {
      // 应用主题配置
      const mode = result?.config?.themeMode
      if (mode === 'light' || mode === 'dark' || mode === 'auto') {
        setThemeMode(mode)
      }
      // 特意设计：每次启动都强制开启 SFW 模式，不从持久化配置恢复
      // 原因：SFW 是安全默认值，即使上次会话关闭了 SFW，本次启动也必须以安全状态开始
      //       避免封面图在启动时被意外加载（尤其适用于公共 / 截屏场景）
      //       用户可在会话中通过设置页面或 Toast 按钮主动关闭 SFW
      setSfwMode(true)
      setConfig('sfwMode', true).catch(() => {})
      setShowSfwToast(true)
      // Load tag blacklist from config
      const rawBlacklist = result.config?.tagBlacklist
      if (rawBlacklist && typeof rawBlacklist === 'object') {
        const normalized: { hcomic: string[]; moeimg: string[] } = {
          hcomic: Array.isArray((rawBlacklist as Record<string, unknown>).hcomic) ? (rawBlacklist as Record<string, unknown>).hcomic as string[] : [],
          moeimg: Array.isArray((rawBlacklist as Record<string, unknown>).moeimg) ? (rawBlacklist as Record<string, unknown>).moeimg as string[] : [],
        }
        setTagBlacklist(normalized)
      }
      // Subscribe to blacklist changes for persistence
      if (!subscribedRef.current) {
        subscribedRef.current = true
        unsubRef.current = subscribeToBlacklistChanges(setConfig)
      }
    }).catch(() => {
      setSfwMode(true)
      setShowSfwToast(true)
    })
    return () => {
      unsubRef.current?.()
      unsubRef.current = null
      subscribedRef.current = false
    }
  }, [setThemeMode, setSfwMode, setConfig, getConfig, setTagBlacklist])

  const handleDisableSfw = useCallback(() => {
    setSfwMode(false)
    setConfig('sfwMode', false).catch(() => {})
    setShowSfwToast(false)
    dismissSfwToast()
  }, [setSfwMode, setConfig, dismissSfwToast])

  const handleDismissToast = useCallback(() => {
    setShowSfwToast(false)
    dismissSfwToast()
  }, [dismissSfwToast])

  const [activePage, setActivePage] = useState('search')
  const [scrollTarget, setScrollTarget] = useState<string | null>(null)
  const { pendingSearch } = useDrawerStore()
  const { readerComic, closeReader } = useReaderStore()

  useEffect(() => {
    if (pendingSearch && activePage !== 'search') {
      setActivePage('search')
    }
  }, [pendingSearch, activePage])

  const renderPage = () => {
    switch (activePage) {
      case 'search':
        return <SearchPage />
      case 'downloads':
        return <DownloadPage />
      case 'favourites':
        return <FavouritesPage onNavigateToSettings={() => { setActivePage('settings'); setScrollTarget('login') }} />
      case 'settings':
        return <SettingsPage scrollTarget={scrollTarget} onScrollDone={() => setScrollTarget(null)} />
      default:
        return <div className="text-[var(--text-primary)]">Unknown page</div>
    }
  }

  return (
    <div className="flex h-screen bg-[var(--bg-secondary)]">
      <Toast
        message="当前处于 SFW 模式，封面已隐藏"
        actionLabel="关闭 SFW"
        onAction={handleDisableSfw}
        onDismiss={handleDismissToast}
        visible={showSfwToast && !sfwToastDismissed}
      />
      <Sidebar activePage={activePage} onPageChange={setActivePage} />
      <div className="flex-1 flex flex-col overflow-hidden">
        <main className="flex-1 overflow-auto px-6 py-3">
          {renderPage()}
        </main>
      </div>
      <ComicInfoDrawer />
      <ComicReaderModal
        comic={readerComic}
        open={!!readerComic}
        onClose={closeReader}
      />
    </div>
  )
}

export default App

import { useEffect, useState, useCallback } from 'react'
import { SearchMode, IPC_ERROR_CODES } from '@shared/types'
import { useDrawerStore } from '../stores/useDrawerStore'
import { useSettingsStore } from '../stores/useSettingsStore'
import { useAddToFavourites, useRemoveFromFavourites, useCheckFavourite } from '../hooks/useIpc'
import { Toast } from './common/Toast'

export function ComicInfoDrawer() {
  const { drawerComic, isOpen, closeDrawer, setPendingSearch } = useDrawerStore()
  const { tagBlacklist, addTag, removeTag } = useSettingsStore()
  const { addToFavourites } = useAddToFavourites()
  const { removeFromFavourites } = useRemoveFromFavourites()
  const { checkFavourite } = useCheckFavourite()
  const [mounted, setMounted] = useState(false)
  const [visible, setVisible] = useState(false)
  const [confirmTag, setConfirmTag] = useState<{ tag: string; action: 'block' | 'unblock' } | null>(null)
  const [favouritesState, setFavouritesState] = useState<'idle' | 'loading' | 'success' | 'error'>('idle')
  const [favToastMessage, setFavToastMessage] = useState('')
  const [showFavToast, setShowFavToast] = useState(false)

  const comicSource = drawerComic?.sourceSite || 'hcomic'

  const isTagBlocked = (tag: string) => {
    const key = (comicSource === 'moeimg' ? 'moeimg' : 'hcomic') as 'hcomic' | 'moeimg'
    return tagBlacklist[key].some(t => t.toLowerCase() === tag.toLowerCase())
  }

  useEffect(() => {
    if (isOpen) {
      setMounted(true)
      requestAnimationFrame(() => setVisible(true))
    } else {
      setVisible(false)
    }
  }, [isOpen])

  useEffect(() => {
    if (!isOpen || !drawerComic?.id || comicSource !== 'hcomic') {
      setFavouritesState('idle')
      return
    }
    let cancelled = false
    setFavouritesState('loading')
    checkFavourite(drawerComic.id)
      .then((result: { isFavourited: boolean }) => {
        if (!cancelled) {
          setFavouritesState(result.isFavourited ? 'success' : 'idle')
        }
      })
      .catch(() => {
        if (!cancelled) {
          setFavouritesState('idle')
        }
      })
    return () => { cancelled = true }
  }, [isOpen, drawerComic?.id, comicSource])

  const handleTransitionEnd = useCallback(() => {
    if (!visible) {
      setMounted(false)
    }
  }, [visible])

  useEffect(() => {
    if (!isOpen) return
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') closeDrawer()
    }
    document.addEventListener('keydown', handler)
    return () => document.removeEventListener('keydown', handler)
  }, [isOpen, closeDrawer])

  const handleSearch = (query: string, mode: SearchMode, append = false) => {
    setPendingSearch(query, mode, append)
    closeDrawer()
  }

  const handleToggleFavourites = async () => {
    if (!drawerComic?.id || favouritesState === 'loading') return
    const isFavourited = favouritesState === 'success'
    setFavouritesState('loading')
    try {
      if (isFavourited) {
        await removeFromFavourites(drawerComic.id)
        setFavouritesState('idle')
        setFavToastMessage('已移除收藏')
      } else {
        await addToFavourites(drawerComic.id)
        setFavouritesState('success')
        setFavToastMessage('已加入收藏夹')
      }
      setShowFavToast(true)
    } catch (err: unknown) {
      const error = err as Error & { code?: number }
      if (error.code === IPC_ERROR_CODES.AUTH_REQUIRED) {
        setFavouritesState(isFavourited ? 'success' : 'error')
        setFavToastMessage('请先登录后再操作')
      } else {
        setFavouritesState(isFavourited ? 'success' : 'error')
        setFavToastMessage(isFavourited ? '移除收藏失败' : '加入收藏夹失败')
      }
      setShowFavToast(true)
    }
  }

  useEffect(() => {
    if (!showFavToast) return
    const timer = setTimeout(() => {
      setShowFavToast(false)
      if (favouritesState === 'error') {
        setFavouritesState('idle')
      }
    }, 3000)
    return () => clearTimeout(timer)
  }, [showFavToast, favouritesState])

  if (!mounted) return null

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      <Toast
        message={favToastMessage}
        visible={showFavToast}
        onDismiss={() => setShowFavToast(false)}
      />
      <div
        className={`absolute inset-0 transition-opacity duration-300 ${
          visible ? 'bg-black/50' : 'bg-black/0'
        }`}
        onClick={closeDrawer}
      />
      <div
        onTransitionEnd={handleTransitionEnd}
        className={`relative w-80 max-w-[85vw] bg-[var(--bg-primary)] shadow-2xl
                    flex flex-col overflow-y-auto
                    transition-transform duration-300 ease-out ${
                      visible ? 'translate-x-0' : 'translate-x-full'
                    }`}
      >
        <div className="flex items-center justify-between px-5 py-4 border-b border-[var(--border)]">
          <span className="text-sm text-[var(--text-secondary)]">漫画详情</span>
          <button
            onClick={closeDrawer}
            className="w-7 h-7 flex items-center justify-center rounded-md
                       text-[var(--text-secondary)] hover:bg-[var(--bg-secondary)]
                       hover:text-[var(--text-primary)] transition-colors text-lg"
          >
            ✕
          </button>
        </div>

        <div className="px-5 py-4 space-y-4">
          <h3 className="text-base font-medium text-[var(--text-primary)] leading-relaxed select-text">
            {drawerComic?.title}
          </h3>

          {drawerComic?.author ? (
            <div>
              <span className="text-xs text-[var(--text-secondary)]">作者</span>
              <button
                onClick={() => handleSearch(drawerComic.author!, 'author')}
                className="block text-sm text-[var(--accent)] mt-0.5 cursor-pointer
                           hover:underline select-text text-left"
              >
                {drawerComic.author}
              </button>
            </div>
          ) : (
            <div>
              <span className="text-xs text-[var(--text-secondary)]">作者</span>
              <p className="text-sm text-[var(--text-secondary)] mt-0.5">未知作者</p>
            </div>
          )}

          <div>
            <span className="text-xs text-[var(--text-secondary)]">信息</span>
            <div className="flex items-center gap-2 mt-0.5">
              <p className="text-sm text-[var(--text-primary)] select-text">
                {drawerComic?.sourceSite || drawerComic?.source}
                {drawerComic?.pages != null && drawerComic.pages > 0 && (
                  <> · {drawerComic.pages} 页</>
                )}
              </p>
              {drawerComic?.url && (
                <button
                  onClick={() => window.hcomic.openUrl(drawerComic.url)}
                  className="text-xs px-2 py-0.5 rounded-md bg-[var(--accent)]/10 text-[var(--accent)]
                             hover:bg-[var(--accent)]/20 transition-colors flex-shrink-0"
                  title={drawerComic.url}
                >
                  打开原网页
                </button>
              )}
            </div>
          </div>

          {comicSource === 'hcomic' && (
            <div>
              <button
                onClick={handleToggleFavourites}
                disabled={favouritesState === 'loading'}
                className={`flex items-center gap-1.5 text-sm px-3 py-1.5 rounded-lg transition-colors ${
                  favouritesState === 'success'
                    ? 'bg-pink-500/10 text-pink-500 hover:bg-pink-500/20'
                    : 'bg-[var(--accent)]/10 text-[var(--accent)] hover:bg-[var(--accent)]/20'
                } disabled:opacity-60`}
              >
                <svg
                  className="w-4 h-4 flex-shrink-0"
                  viewBox="0 0 24 24"
                  fill={favouritesState === 'success' ? 'currentColor' : 'none'}
                  stroke="currentColor"
                  strokeWidth={2}
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    d="M21 8.25c0-2.485-2.099-4.5-4.688-4.5-1.935 0-3.597 1.126-4.312 2.733-.715-1.607-2.377-2.733-4.313-2.733C5.1 3.75 3 5.765 3 8.25c0 7.22 9 12 9 12s9-4.78 9-12z"
                  />
                </svg>
                <span>
                  {favouritesState === 'loading'
                    ? '处理中...'
                    : favouritesState === 'success'
                      ? '已加入收藏'
                      : '加入收藏'}
                </span>
              </button>
            </div>
          )}

          {drawerComic?.tags && drawerComic.tags.length > 0 && (
            <div>
              <span className="text-xs text-[var(--text-secondary)]">标签</span>
              <div className="flex flex-wrap gap-1.5 mt-2">
                {drawerComic.tags.map((tag, i) => {
                  const blocked = isTagBlocked(tag)
                  return (
                    <span key={i} className="relative group">
                      <button
                        onClick={() => handleSearch(tag, 'tag', true)}
                        className={`text-xs px-2.5 py-1 rounded-full cursor-pointer transition-colors ${
                          blocked
                            ? 'bg-[var(--error)]/10 text-[var(--error)] line-through opacity-60'
                            : 'bg-[var(--accent)]/10 text-[var(--accent)] hover:bg-[var(--accent)]/20'
                        }`}
                      >
                        {tag}
                      </button>
                      <button
                        onClick={() => setConfirmTag({ tag, action: blocked ? 'unblock' : 'block' })}
                        className={`absolute -top-1 -right-1 w-4 h-4 rounded-full text-[10px] flex items-center justify-center
                                   opacity-0 group-hover:opacity-100 transition-opacity
                                   ${blocked
                                     ? 'bg-[var(--accent)] text-white'
                                     : 'bg-[var(--error)] text-white'
                                   }`}
                        title={blocked ? '取消屏蔽' : '屏蔽标签'}
                      >
                        {blocked ? '✓' : '×'}
                      </button>
                    </span>
                  )
                })}
              </div>
            </div>
          )}
        </div>
      </div>

      {confirmTag && (
        <div className="fixed inset-0 z-[60] bg-black/50 flex items-center justify-center" onClick={() => setConfirmTag(null)}>
          <div className="bg-[var(--bg-primary)] rounded-xl p-6 shadow-lg max-w-sm w-full" onClick={(e) => e.stopPropagation()}>
            <h3 className="text-base font-medium text-[var(--text-primary)] mb-4">
              {confirmTag.action === 'block'
                ? `屏蔽标签「${confirmTag.tag}」？`
                : `取消屏蔽标签「${confirmTag.tag}」？`
              }
            </h3>
            <p className="text-sm text-[var(--text-secondary)] mb-4">
              {confirmTag.action === 'block'
                ? '包含该标签的漫画将从搜索结果中隐藏。'
                : '包含该标签的漫画将恢复显示在搜索结果中。'
              }
            </p>
            <div className="flex justify-end gap-2">
              <button
                onClick={() => setConfirmTag(null)}
                className="px-4 py-2 rounded-lg bg-[var(--bg-secondary)] border border-[var(--border)] text-[var(--text-primary)]"
              >
                取消
              </button>
              <button
                onClick={() => {
                  if (confirmTag.action === 'block') {
                    addTag(comicSource, confirmTag.tag)
                  } else {
                    removeTag(comicSource, confirmTag.tag)
                  }
                  setConfirmTag(null)
                }}
                className={`px-4 py-2 rounded-lg text-white ${
                  confirmTag.action === 'block'
                    ? 'bg-[var(--error)] hover:bg-[var(--error)]/80'
                    : 'bg-[var(--accent)] hover:bg-[var(--accent-hover)]'
                }`}
              >
                确认
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

import { useCallback, useEffect, useRef, useState } from 'react'
import { ComicInfo } from '@shared/types'
import { useComicReader } from '../hooks/useComicReader'
import { useReaderSettings, type BlankPosition } from '../hooks/useReaderSettings'
import { usePreloadManager } from '../hooks/usePreloadManager'
import { usePageTracking } from '../hooks/usePageTracking'
import { PageFlipView } from './PageFlipView'
import { ReaderPage } from './ReaderPage'

const ZOOM_MIN = 0.25
const ZOOM_MAX = 4.0
const ZOOM_STEP = 0.1

interface ComicReaderModalProps {
  comic: ComicInfo | null
  open: boolean
  onClose: () => void
}

export function ComicReaderModal({ comic, open, onClose }: ComicReaderModalProps) {
  const {
    imageUrls,
    totalPages,
    currentPage,
    loadingState,
    errorMessage,
    fetchUrls,
    setCurrentPage,
    reset,
  } = useComicReader()

  const { pageGap, imageWidth, setPageGap, setImageWidth, displayMode, setDisplayMode } = useReaderSettings()
  const [blankPosition, setBlankPosition] = useState<BlankPosition>('none')
  const effectiveTotalPages = displayMode === 'double' && blankPosition === 'front' ? totalPages + 1 : totalPages
  const [settingsOpen, setSettingsOpen] = useState(false)
  const [zoom, setZoom] = useState(1)
  const [mounted, setMounted] = useState(false)
  const [visible, setVisible] = useState(false)

  useEffect(() => {
    if (open) {
      setMounted(true)
      // 双层 RAF：等待 DOM mount + 浏览器完成样式计算后再触发 CSS transition
      requestAnimationFrame(() => {
        requestAnimationFrame(() => setVisible(true))
      })
    } else {
      setVisible(false)
    }
  }, [open])

  const handleTransitionEnd = useCallback(() => {
    if (!visible) {
      setMounted(false)
    }
  }, [visible])

  const [isDragging, setIsDragging] = useState(false)
  const dragPageRef = useRef(0)
  const sliderRef = useRef<HTMLDivElement>(null)

  const {
    imageCacheRef,
    cacheVersion,
    preloadTarget,
    setPreloadTarget,
    clearCache,
  } = usePreloadManager(imageUrls, loadingState)

  const scrollContainerRef = useRef<HTMLDivElement>(null)
  const pageRefs = useRef<(HTMLDivElement | null)[]>([])
  const settingsPanelRef = useRef<HTMLDivElement>(null)

  usePageTracking(
    pageRefs, scrollContainerRef, isDragging, currentPage, setCurrentPage,
    loadingState, imageUrls.length,
  )

  // Close settings panel on outside click
  useEffect(() => {
    if (!settingsOpen) return
    const handler = (e: MouseEvent) => {
      if (settingsPanelRef.current?.contains(e.target as Node)) return
      const btn = (e.target as Element).closest('[aria-label="阅读设置"]')
      if (btn) return
      setSettingsOpen(false)
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [settingsOpen])

  const zoomIn = useCallback(() => {
    setZoom(z => Math.min(ZOOM_MAX, +(z + ZOOM_STEP).toFixed(1)))
  }, [])

  const zoomOut = useCallback(() => {
    setZoom(z => Math.max(ZOOM_MIN, +(z - ZOOM_STEP).toFixed(1)))
  }, [])

  const resetZoom = useCallback(() => {
    setZoom(1)
  }, [])

  const handleSetDisplayMode = useCallback((mode: typeof displayMode) => {
    setDisplayMode(mode)
    if (mode !== 'double') setBlankPosition('none')
  }, [setDisplayMode])

  // Ctrl+Wheel zoom
  useEffect(() => {
    if (!open) return
    const handler = (e: WheelEvent) => {
      if (e.ctrlKey) {
        e.preventDefault()
        if (e.deltaY < 0) zoomIn()
        else if (e.deltaY > 0) zoomOut()
      }
    }
    window.addEventListener('wheel', handler, { passive: false })
    return () => window.removeEventListener('wheel', handler)
  }, [open, zoomIn, zoomOut])

  // Fetch URLs when modal opens
  useEffect(() => {
    if (open && comic) {
      fetchUrls(comic)
    } else {
      reset()
      clearCache()
    }
  }, [open, comic?.id, fetchUrls, reset, clearCache])

  // Keyboard handler
  useEffect(() => {
    if (!open) return
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        onClose()
      } else if ((e.key === '=' || e.key === '+') && e.ctrlKey) {
        e.preventDefault()
        zoomIn()
      } else if (e.key === '-' && e.ctrlKey) {
        e.preventDefault()
        zoomOut()
      } else if (e.key === '0' && e.ctrlKey) {
        e.preventDefault()
        resetZoom()
      } else if (displayMode === 'scroll') {
        if (e.key === 'ArrowDown' || e.key === ' ') {
          e.preventDefault()
          scrollContainerRef.current?.scrollBy({ top: 300, behavior: 'smooth' })
        } else if (e.key === 'ArrowUp') {
          e.preventDefault()
          scrollContainerRef.current?.scrollBy({ top: -300, behavior: 'smooth' })
        }
      } else {
        const step = displayMode === 'double' ? 2 : 1
        const navTotal = displayMode === 'double' && blankPosition === 'front' ? totalPages + 1 : totalPages
        if (e.key === 'ArrowRight' || e.key === 'ArrowDown' || e.key === ' ' || e.key === 'PageDown') {
          e.preventDefault()
          if (currentPage + step <= navTotal) {
            setCurrentPage(currentPage + step)
          }
        } else if (e.key === 'ArrowLeft' || e.key === 'ArrowUp' || e.key === 'PageUp') {
          e.preventDefault()
          if (currentPage > 1) {
            setCurrentPage(Math.max(currentPage - step, 1))
          }
        }
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [open, onClose, displayMode, blankPosition, currentPage, totalPages, setCurrentPage])

  // Align currentPage to odd in double mode
  // Intentionally reads currentPage from closure without listing it as a dependency.
  // Only align on displayMode change; adding currentPage would cause infinite re-runs.
  useEffect(() => {
    if (displayMode === 'double' && currentPage > 1 && currentPage % 2 === 0) {
      setCurrentPage(currentPage - 1)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [displayMode])

  if (!mounted) return null

  const progress = effectiveTotalPages > 0 ? Math.round((currentPage / effectiveTotalPages) * 100) : 0

  const handleSliderPointerDown = (e: React.PointerEvent) => {
    e.preventDefault()
    ;(e.currentTarget as HTMLElement).setPointerCapture(e.pointerId)
    setIsDragging(true)
    updateDragPosition(e)
  }

  const handleSliderPointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return
    updateDragPosition(e)
  }

  const handleSliderPointerUp = () => {
    if (!isDragging) return
    setIsDragging(false)
    if (dragPageRef.current > 0) {
      setPreloadTarget(dragPageRef.current)
    }
  }

  const updateDragPosition = (e: React.PointerEvent) => {
    const track = sliderRef.current
    if (!track) return
    const rect = track.getBoundingClientRect()
    const pct = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width))
    const page = Math.max(1, Math.round(pct * effectiveTotalPages))
    dragPageRef.current = page
    pageRefs.current[page - 1]?.scrollIntoView({ behavior: 'instant' })
    setCurrentPage(page)
  }

  return (
    <div className="fixed inset-0 z-50">
      {/* 半透明遮罩层，点击可关闭 */}
      <div
        className={`absolute inset-0 bg-black transition-opacity duration-300 ${
          visible ? 'opacity-50' : 'opacity-0'
        }`}
        onClick={onClose}
      />
      {/* 模态内容层，垂直方向滑入滑出 */}
      <div
        onTransitionEnd={handleTransitionEnd}
        className={`absolute inset-0 flex flex-col bg-[#1a1a2e] transition-transform duration-300 ease-out ${
          visible ? 'translate-y-0' : 'translate-y-full'
        }`}
      >
      {/* Header */}
      <div
        className="flex items-center justify-between px-5 py-3 shrink-0"
        style={{ background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(8px)' }}
      >
        <div className="flex items-center gap-3">
          <button
            onClick={onClose}
            className="px-3 py-1.5 rounded-md text-white text-sm hover:bg-white/10 transition-colors"
            style={{ background: 'rgba(255,255,255,0.1)' }}
          >
            关闭
          </button>
          <span className="text-sm text-gray-400 truncate max-w-[300px]">{comic?.title}</span>
        </div>
        <span
          className="px-2.5 py-1 rounded-full text-xs text-white"
          style={{ background: 'rgba(255,255,255,0.15)' }}
        >
          {currentPage} / {effectiveTotalPages}
        </span>
      </div>

      {/* Content */}
      {displayMode === 'scroll' ? (
        <div ref={scrollContainerRef} className="flex-1 overflow-y-auto">
          {(loadingState === 'loading' || loadingState === 'idle') && (
            <ReaderLoadingState className="h-full" />
          )}
          {loadingState === 'error' && (
            <ReaderErrorState message={errorMessage} onClose={onClose} className="h-full" />
          )}
          {loadingState === 'loaded' && imageUrls.length === 0 && (
            <ReaderEmptyState onClose={onClose} className="h-full" />
          )}
          {loadingState === 'loaded' && imageUrls.length > 0 && (
            <div className="flex flex-col items-center py-2" style={{ gap: pageGap + 'px' }}>
              {imageUrls.map((url, idx) => {
                const cachedDataUri = imageCacheRef.current.get(idx)
                return (
                <div
                  key={idx}
                  ref={(el) => { pageRefs.current[idx] = el }}
                  style={{ width: Math.min(imageWidth * zoom, 100) + '%' }}
                >
                  <ReaderPage
                    url={url}
                    index={idx}
                    priority={preloadTarget != null && Math.abs(idx + 1 - preloadTarget) <= 5}
                    cachedDataUri={cachedDataUri}
                  />
                </div>
                )
              })}
            </div>
          )}
        </div>
      ) : (
        <>
          {(loadingState === 'loading' || loadingState === 'idle') && (
            <ReaderLoadingState className="flex-1" />
          )}
          {loadingState === 'error' && (
            <ReaderErrorState message={errorMessage} onClose={onClose} className="flex-1" />
          )}
          {loadingState === 'loaded' && imageUrls.length === 0 && (
            <ReaderEmptyState onClose={onClose} className="flex-1" />
          )}
          {loadingState === 'loaded' && imageUrls.length > 0 && (
            <PageFlipView
              imageUrls={imageUrls}
              totalPages={totalPages}
              currentPage={currentPage}
              setCurrentPage={setCurrentPage}
              displayMode={displayMode}
              imageWidth={imageWidth}
              zoom={zoom}
              imageCacheRef={imageCacheRef}
              cacheVersion={cacheVersion}
              onPageChange={(page) => setPreloadTarget(page)}
              blankPosition={blankPosition}
            />
          )}
        </>
      )}

      {/* Footer */}
      <div
        className="px-5 py-2 shrink-0 relative"
        style={{ background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(8px)' }}
      >
        <div className="flex items-center gap-3">
          <span className="text-xs text-gray-500">{currentPage} / {effectiveTotalPages}</span>
          <div
            ref={sliderRef}
            data-track
            role="slider"
            aria-valuemin={1}
            aria-valuemax={effectiveTotalPages}
            aria-valuenow={currentPage}
            aria-label="页面进度"
            className="flex-1 h-6 flex items-center cursor-pointer"
            style={{ padding: '8px 0' }}
            onPointerDown={handleSliderPointerDown}
            onPointerMove={handleSliderPointerMove}
            onPointerUp={handleSliderPointerUp}
            onPointerCancel={() => setIsDragging(false)}
            onLostPointerCapture={() => setIsDragging(false)}
          >
            <div className="w-full relative" style={{ height: '4px' }}>
              <div className="absolute inset-0 rounded-full" style={{ background: 'rgba(255,255,255,0.1)' }} />
              <div
                className="absolute left-0 top-0 bottom-0 rounded-full"
                style={{ width: `${progress}%`, background: '#6c8cff' }}
              />
              <div
                className="absolute top-1/2 rounded-full"
                style={{
                  left: `${progress}%`,
                  transform: 'translate(-50%, -50%)',
                  width: isDragging ? 18 : 14,
                  height: isDragging ? 18 : 14,
                  background: '#6c8cff',
                  boxShadow: '0 0 6px rgba(108,140,255,0.5)',
                  transition: isDragging ? 'none' : 'left 0.2s, width 0.15s, height 0.15s',
                  ...(isDragging ? { touchAction: 'none' } : {}),
                }}
              />
            </div>
          </div>
          <span className="text-xs text-gray-500">
            {displayMode === 'scroll' ? 'ESC 关闭 | ↑↓ 滚动' : 'ESC 关闭 | ←→ 翻页'}
          </span>
          <button
            aria-label="阅读设置"
            onClick={() => setSettingsOpen(!settingsOpen)}
            className="p-1 rounded hover:bg-white/10 transition-colors"
            style={{ color: settingsOpen ? '#6c8cff' : 'rgba(255,255,255,0.5)' }}
          >
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
              <circle cx="8" cy="8" r="2.5" />
              <path d="M8 1.5v1.5M8 13v1.5M1.5 8h1.5M13 8h1.5M3.05 3.05l1.06 1.06M11.89 11.89l1.06 1.06M3.05 12.95l1.06-1.06M11.89 4.11l1.06-1.06" />
            </svg>
          </button>
        </div>

        {settingsOpen && (
          <div
            ref={settingsPanelRef}
            className="absolute bottom-full right-4 mb-2 rounded-lg"
            style={{
              background: 'rgba(0,0,0,0.6)',
              backdropFilter: 'blur(8px)',
              padding: '12px 16px',
              width: '220px',
            }}
          >
            <div className="flex flex-col gap-3">
              {/* Display mode switcher */}
              <div className="flex rounded-md overflow-hidden" style={{ background: 'rgba(255,255,255,0.05)' }}>
                <ModeButton
                  label="连续滚动"
                  icon={scrollIcon}
                  active={displayMode === 'scroll'}
                  onClick={() => handleSetDisplayMode('scroll')}
                />
                <ModeButton
                  label="单页显示"
                  icon={singleIcon}
                  active={displayMode === 'single'}
                  onClick={() => handleSetDisplayMode('single')}
                />
                <ModeButton
                  label="双页显示"
                  icon={doubleIcon}
                  active={displayMode === 'double'}
                  onClick={() => handleSetDisplayMode('double')}
                />
              </div>
              {displayMode === 'double' && (
                <div className="flex rounded-md overflow-hidden" style={{ background: 'rgba(255,255,255,0.05)' }}>
                  <ModeButton
                    label="无补白"
                    icon={blankNoneIcon}
                    active={blankPosition === 'none'}
                    onClick={() => setBlankPosition('none')}
                  />
                  <ModeButton
                    label="前补白"
                    icon={blankFrontIcon}
                    active={blankPosition === 'front'}
                    onClick={() => setBlankPosition('front')}
                  />
                  <ModeButton
                    label="后补白"
                    icon={blankEndIcon}
                    active={blankPosition === 'end'}
                    onClick={() => setBlankPosition('end')}
                  />
                </div>
              )}
              {displayMode === 'scroll' && (
                <>
                  <label className="flex items-center justify-between gap-2 text-xs text-gray-300">
                    <span>页面间距</span>
                    <span className="text-gray-500" style={{ minWidth: '32px', textAlign: 'right' }}>{pageGap}px</span>
                  </label>
                  <input
                    aria-label="页面间距"
                    type="range"
                    min={0}
                    max={80}
                    step={2}
                    value={pageGap}
                    onChange={(e) => setPageGap(Number(e.target.value))}
                    className="w-full accent-[#6c8cff]"
                  />
                </>
              )}
              <label className="flex items-center justify-between gap-2 text-xs text-gray-300">
                <span>图片宽度</span>
                <span className="text-gray-500" style={{ minWidth: '32px', textAlign: 'right' }}>{imageWidth}%</span>
              </label>
              <input
                aria-label="图片宽度"
                type="range"
                min={30}
                max={100}
                step={1}
                value={imageWidth}
