  }

  return {
    app: {
      whenReady: vi.fn().mockResolvedValue(undefined),
      on: vi.fn(),
      quit: vi.fn(),
      getName: vi.fn().mockReturnValue('HComicDownloader'),
      setAsDefaultProtocolClient: vi.fn(),
    },
    BrowserWindow: MockBrowserWindow,
    ipcMain: {
      handle: mockHandle
    },
    shell: {
